// Split the logo into two pieces so each can be animated independently. Both are
// rendered as full-size overlapping <svg> elements sharing the same viewBox, so at
// rest they compose back into the exact original lockup.
const BADGE_START = LOGO_INNER.indexOf('<path class="am-badge"');
const WORDMARK_INNER = LOGO_INNER.slice(0, BADGE_START);
const BADGE_INNER = LOGO_INNER.slice(BADGE_START);

/**
 * Full-screen brand intro loader: the badge fades/scales in, the wordmark
 * slides into place and breathes, then the overlay fades out 2s after load.
 * Mounted once at the app root (app/layout.tsx).
 *
 * Animations are applied to the whole <svg> elements (HTML replaced elements),
 * NOT to inner SVG <g>/<path> nodes — animating SVG internals with percentage
 * transforms + transform-box renders static on mobile WebKit/Chrome.
 */
export default function AlMajdouieLoader() {
  const [isDone, setIsDone] = useState(false);

  useEffect(() => {
    let timer: ReturnType<typeof setTimeout>;
    const handleLoaded = () => {
      timer = setTimeout(() => setIsDone(true), 2000);
    };
    if (document.readyState === "complete") {
      handleLoaded();
    } else {
      window.addEventListener("load", handleLoaded);
    }
    return () => {
      clearTimeout(timer);
      window.removeEventListener("load", handleLoaded);
    };
  }, []);

  return (
    <>
      <style>{`
        .am-loader {
          position: fixed;
          inset: 0;
          background: #f5f2ea;
          display: flex;
          align-items: center;
          justify-content: center;
          z-index: 9999;
          transition: opacity 0.6s ease, visibility 0s 0.6s;
        }
        .am-loader.is-done {
          opacity: 0;
          visibility: hidden;
          pointer-events: none;
        }
        .am-logo {
          position: relative;
          width: 90%;
          max-width: 520px;
          aspect-ratio: 383.05 / 235.41;
          overflow: hidden;
        }
        .am-layer {
          position: absolute;
          inset: 0;
          width: 100%;
          height: 100%;
          will-change: transform, opacity;
        }
        .am-badge-svg {
          transform-origin: 75% 50%;
          opacity: 0;
          transform: scale(0.9);
          animation:
            am-badge-in 0.9s cubic-bezier(0.22, 1, 0.36, 1) 0.1s forwards,
            am-breathe 4s ease-in-out 2.8s infinite;
        }
        .am-wordmark-svg {
          opacity: 0;
          transform: translateX(24%);
          animation: am-wordmark-slide 1.15s cubic-bezier(0.25, 1, 0.32, 1) 0.7s forwards;
        }
        @keyframes am-badge-in { to { opacity: 1; transform: scale(1); } }
        @keyframes am-wordmark-slide {
          from { opacity: 0; transform: translateX(24%); }
          to { opacity: 1; transform: translateX(0); }
        }
        @keyframes am-breathe {
          0%, 100% { transform: scale(1); }
          50% { transform: scale(1.025); }
        }
        @media (prefers-reduced-motion: reduce) {
          .am-badge-svg, .am-wordmark-svg { animation: none; opacity: 1; transform: none; }
        }
      `}</style>

      <div className={`am-loader ${isDone ? "is-done" : ""}`} aria-hidden>
        <div className="am-logo" role="img" aria-label="مؤسسة المجدوعي الخيرية">
          <svg
            className="am-layer am-wordmark-svg"
            viewBox="0 0 383.05 235.41"
            xmlns="http://www.w3.org/2000/svg"
            dangerouslySetInnerHTML={{ __html: WORDMARK_INNER }}
          />
          <svg
            className="am-layer am-badge-svg"
            viewBox="0 0 383.05 235.41"
            xmlns="http://www.w3.org/2000/svg"
            dangerouslySetInnerHTML={{ __html: BADGE_INNER }}
          />
        </div>
      </div>
    </>
  );
}
